#include<bits/stdc++.h>
using namespace std;

int a[100005], b[100005];

void Merge_Sort(int a[], int l, int r)
{
	if(l >= r)
		return;
    int mid = (l + r) >> 1;
	Merge_Sort(a, l, mid);
    Merge_Sort(a, mid + 1, r);
    int s = l, t = mid + 1, cur = l;
    while(s <= mid && t <= r)
    {
        if(a[s] < a[t])
            b[cur++] = a[s++];
        else
            b[cur++] = a[t++];
    }
    while(s <= mid)
        b[cur++] = a[s++];
    while(t <= r)
        b[cur++] = a[t++];
    copy(b + l, b + r + 1, a + l);
}

int main()
{
	int n;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> a[i];
	Merge_Sort(a, 1, n);
	for(int i = 1; i <= n; i++)
		cout << a[i] << ' ';
	return 0;
}
